function detectCycle(head) {
    if (!head || !head.next) return null;
    let slow = head, fast = head;
    // First phase: determine whether a cycle exists
    while (fast && fast.next) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow === fast) break;
    }
    // No cycle detected
    if (!fast || !fast.next) return null;
    // Second phase: find the start of the cycle
    slow = head;
    while (slow !== fast) {
        slow = slow.next;
        fast = fast.next;
    }
    return slow;
}

function solve(input) {
    let lines = input.trim().split('\n');
    let t = parseInt(lines[0].trim());
    let results = [];
    let index = 1;
    for (let i = 0; i < t; i++) {
        let n = parseInt(lines[index++].trim());
        let values = lines[index++].trim().split(' ').map(Number);
        let cyclePos = parseInt(lines[index++].trim()); // 1-indexed; if 0 then no cycle
        if (n === 0) {
            results.push("0");
            continue;
