        // Build linked list
        let head = new ListNode(values[0]);
        let current = head;
        let nodes = [head]; // store nodes for cycle connection
        for (let j = 1; j < n; j++) {
            let newNode = new ListNode(values[j]);
            current.next = newNode;
            current = newNode;
            nodes.push(newNode);
        }
        // Create cycle if cyclePos is not 0
        if (cyclePos !== 0) {
            // cyclePos is 1-indexed
            let cycleNode = nodes[cyclePos - 1];
            current.next = cycleNode;
        }
        // Detect cycle starting node
